  `moa_qualite` int DEFAULT NULL,
  `moa_qualite_autre` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `moa_construction` tinyint(1) DEFAULT NULL,
  `moa_construction_pro` tinyint(1) DEFAULT NULL,
  `moa_construction_pro_champ` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `moa_nature_travaux_json` text COLLATE utf8mb4_general_ci COMMENT 'Valeurs JSON du tableau Nature des travaux',
  PRIMARY KEY (`DOID`),
  KEY `moa_qualite` (`moa_qualite`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

